/**
 * @fileoverview Uploader state — pure queue-management functions.
 * @module module/Uploader/state
 */

import { STATUS } from './constants.js';

// ── Queue operations ────────────────────────────

/**
 * Add an entry to the queue array.
 *
 * @param {Array} queue — the mutable queue array
 * @param {object} entry — entry created via `createEntry()`
 */
export function addToQueue(queue, entry) {
    queue.push(entry);
}

/**
 * Remove an entry from the queue array.
 * If the entry has an active XHR, it is aborted first.
 *
 * @param {Array} queue — the mutable queue array
 * @param {object} entry — entry to remove
 */
export function removeFromQueue(queue, entry) {
    if (entry.xhr) { entry.xhr.abort(); entry.xhr = null; }
    const idx = queue.indexOf(entry);
    if (idx !== -1) queue.splice(idx, 1);
}

/**
 * Return all entries that are still in the 'queued' status.
 *
 * @param {Array} queue — the queue array
 * @returns {Array} entries with status === 'queued'
 */
export function getQueuedEntries(queue) {
    return queue.filter(e => e.status === STATUS.QUEUED);
}
