/**
 * @fileoverview Uploader helpers — pure utility functions.
 * @module module/Uploader/helpers
 */

import { STATUS } from './constants.js';

// ── Size formatting ─────────────────────────────

/**
 * Format a byte count into a human-readable string.
 *
 * @param {number} bytes — file size in bytes
 * @returns {string} formatted size (e.g. '1.2 MB')
 */
export function fmtSize(bytes) {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / 1048576).toFixed(1) + ' MB';
}

// ── Image preview ───────────────────────────────

/**
 * Read an image file as a data URL for thumbnail preview.
 * Resolves `null` for non-image files or on read error.
 *
 * @param {File} file — the file to read
 * @returns {Promise<string|null>}
 */
export function readPreview(file) {
    return new Promise((resolve) => {
        if (!file.type.startsWith('image/')) { resolve(null); return; }
        const reader = new FileReader();
        reader.onload = () => resolve(reader.result);
        reader.onerror = () => resolve(null);
        reader.readAsDataURL(file);
    });
}

// ── Entry factory ───────────────────────────────

/**
 * Create a new queue entry object for a file.
 *
 * @param {File} file — the file to wrap
 * @param {number} id — unique entry id
 * @returns {{ file: File, id: number, preview: null, status: string, progress: number, xhr: XMLHttpRequest|null }}
 */
export function createEntry(file, id) {
    return {
        file,
        id,
        preview:  null,
        status:   STATUS.QUEUED,
        progress: 0,
        xhr:      null,
    };
}
