/**
 * @fileoverview Uploader events — centralized event binding.
 * @module module/Uploader/events
 */

import razyui from '../../index.js';
import { CLS } from './constants.js';

// ── Drop zone events ────────────────────────────

/**
 * Bind drag-and-drop events to a drop area element.
 *
 * @param {HTMLElement} dropArea — the drop zone element
 * @param {HTMLInputElement} fileInput — the hidden file input
 * @param {Function} onFiles — callback receiving a FileList when files are dropped
 * @param {AbortSignal} [signal] — signal for cleanup via AbortController
 */
export function bindDropZone(dropArea, fileInput, onFiles, signal) {
    const $dropArea = razyui(dropArea);
    const opts = signal ? { signal } : undefined;

    // Clicking the drop zone opens file dialog
    $dropArea.on('click', () => { fileInput.click(); }, opts);

    $dropArea.on('dragenter', (e) => {
        e.preventDefault();
        e.stopPropagation();
        $dropArea.addClass(CLS.DRAGOVER);
    }, opts);

    $dropArea.on('dragleave', (e) => {
        e.preventDefault();
        e.stopPropagation();
        if (!dropArea.contains(e.relatedTarget)) {
            $dropArea.removeClass(CLS.DRAGOVER);
        }
    }, opts);

    $dropArea.on('dragover', (e) => {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'copy';
    }, opts);

    $dropArea.on('drop', (e) => {
        e.preventDefault();
        e.stopPropagation();
        $dropArea.removeClass(CLS.DRAGOVER);
        onFiles(e.dataTransfer.files);
    }, opts);
}

// ── File input events ───────────────────────────

/**
 * Bind the change event on the file input.
 *
 * @param {HTMLInputElement} fileInput — the hidden file input
 * @param {Function} onFiles — callback receiving a FileList when files are selected
 * @param {AbortSignal} [signal] — signal for cleanup via AbortController
 */
export function bindFileInput(fileInput, onFiles, signal) {
    razyui(fileInput).on('change', (e) => {
        onFiles(e.target.files);
        fileInput.value = '';
    }, signal ? { signal } : undefined);
}

// ── Browse button events ───────────────────────────────────

/**
 * Bind the browse button to open the file dialog.
 *
 * @param {HTMLElement} browseBtn — the browse button element
 * @param {HTMLInputElement} fileInput — the hidden file input
 * @param {AbortSignal} [signal] — signal for cleanup via AbortController
 */
export function bindBrowseButton(browseBtn, fileInput, signal) {
    razyui(browseBtn).on('click', () => { fileInput.click(); }, signal ? { signal } : undefined);
}

// ── Delegated remove-button events ─────────────────

/**
 * Bind a delegated click handler on the file list container so that
 * clicks on any remove button trigger the onRemove callback.
 *
 * @param {HTMLElement} listEl — the file list container
 * @param {Function} onRemoveById — callback receiving the entry id string
 * @param {AbortSignal} [signal] — signal for cleanup via AbortController
 */
export function bindListRemove(listEl, onRemoveById, signal) {
    razyui(listEl).on('click', (e) => {
        const rm = razyui(e.target).closest('.' + CLS.REMOVE);
        if (!rm.length) return;
        const row = rm.closest('.' + CLS.FILE);
        if (row.length && row.data('id')) onRemoveById(row.data('id'));
    }, signal ? { signal } : undefined);
}
