/**
 * @fileoverview Uploader component definition for JIT pipeline.
 *
 * Bundles design tokens, state machine config, template slot definitions,
 * and Custom Element metadata.
 *
 * @module module/Uploader.def
 */

import razyui from '../index.js';
import { PART } from './Uploader/constants.js';

/**
 * The definition object for the Uploader component.
 * Contains metadata, tokens, states, templates, variants, and attribute mappings.
 *
 * @type {Object}
 */
export const UploaderDef = {
    name: 'Uploader',
    tag: 'rui-uploader',

    // ═══════════════════════════════════════
    //  Design Tokens
    // ═══════════════════════════════════════
    tokens: {
        prefix: 'up',
        tokens: {
            'drop-gap':        { value: '0.5rem',      description: 'Drop zone gap' },
            'drop-padding-x':  { value: '1rem',         description: 'Drop zone horizontal padding' },
            'drop-padding-y':  { value: '2rem',         description: 'Drop zone vertical padding' },
            'drop-border-width': { value: '2px',        description: 'Drop zone border width' },
            'drop-radius':     { ref: 'radius.lg',      description: 'Drop zone border radius' },
            'icon-font-size':  { value: '1.6rem',       description: 'Upload icon font size' },
            'text-font-size':  { value: '0.85rem',      description: 'Upload text font size' },
            'list-gap':        { value: '6px',           description: 'File list gap' },
            'list-margin-top': { value: '0.75rem',       description: 'File list top margin' },
            'file-gap':        { value: '0.6rem',        description: 'File row gap' },
            'file-padding-x':  { value: '0.65rem',       description: 'File row horizontal padding' },
            'file-padding-y':  { value: '0.5rem',        description: 'File row vertical padding' },
            'file-radius':     { ref: 'radius.md',       description: 'File row border radius' },
            'file-font-size':  { value: '0.82rem',       description: 'File row font size' },
            'thumb-size':      { value: '36px',          description: 'Thumbnail size' },
            'thumb-radius':    { ref: 'radius.sm',       description: 'Thumbnail border radius' },
            'accent':          { ref: 'color.accent',    description: 'Accent color' },
            'accent-subtle':   { ref: 'color.accent-subtle', description: 'Accent subtle' },
            'bg':              { ref: 'color.bg',        description: 'Background' },
            'bg-hover':        { ref: 'color.bg-hover',  description: 'Hover background' },
            'bg-inset':        { ref: 'color.bg-inset',  description: 'Inset background' },
            'border':          { ref: 'color.border',    description: 'Border color' },
            'danger':          { ref: 'color.danger',    description: 'Danger color' },
            'on-accent':       { ref: 'color.on-accent', description: 'Text on accent' },
            'success':         { ref: 'color.success',   description: 'Success color' },
            'text':            { ref: 'color.text',      description: 'Text color' },
            'text-muted':      { ref: 'color.text-muted', description: 'Muted text' },
        },
    },

    // ═══════════════════════════════════════
    //  State Machine
    // ═══════════════════════════════════════
    states: {
        initial: 'idle',
        states: {
            idle: {
                on: { DRAGOVER: 'dragover', UPLOAD: 'uploading' },
            },
            dragover: {
                on: { DRAGLEAVE: 'idle', DROP: 'uploading' },
            },
            uploading: {
                on: { COMPLETE: 'idle' },
            },
        },
        effects: {
            dragover(ctx) {
                if (ctx.dropZone) razyui(ctx.dropZone).addClass('is-dragover');
            },
            idle(ctx) {
                if (ctx.dropZone) razyui(ctx.dropZone).removeClass('is-dragover');
            },
        },
    },

    // ═══════════════════════════════════════
    //  Template Slots
    // ═══════════════════════════════════════
    template: {
        slots: {
            container: { element: 'div', classes: ['uploader'] },
            dropZone:  { element: 'div', classes: ['uploader-drop'] },
            fileList:  { element: 'div', classes: ['uploader-list'] },
            file:      { element: 'div', classes: ['uploader-file'] },
            progress:  { element: 'div', classes: ['uploader-progress'] },
        },
    },

    // ═══════════════════════════════════════
    //  JIT Parts
    // ═══════════════════════════════════════
    jitParts: {
        [PART.ROOT]: PART.ROOT,
        [PART.INPUT]: PART.INPUT,
        [PART.DROP]: PART.DROP,
        [PART.DROP_ICON]: PART.DROP_ICON,
        [PART.DROP_TEXT]: PART.DROP_TEXT,
        [PART.BROWSE]: PART.BROWSE,
        [PART.LIST]: PART.LIST,
        [PART.FILE]: PART.FILE,
        [PART.THUMB]: PART.THUMB,
        [PART.INFO]: PART.INFO,
        [PART.NAME]: PART.NAME,
        [PART.SIZE]: PART.SIZE,
        [PART.PROGRESS]: PART.PROGRESS,
        [PART.PROGRESS_FILL]: PART.PROGRESS_FILL,
        [PART.STATUS]: PART.STATUS,
        [PART.REMOVE]: PART.REMOVE,
    },

    styles: {},

    // ═══════════════════════════════════════
    //  Custom Element
    // ═══════════════════════════════════════
    observedAttrs: ['action', 'accept', 'multiple', 'max-size'],
    attrMap: {
        action:     'action',
        accept:     'accept',
        multiple:   'multiple',
        'max-size': 'maxSize',
    },
};

export default UploaderDef;
