/**
 * @fileoverview Uploader barrel — re-exports from modular implementation.
 * Kept at module root for backward compatibility with razyui.load().
 *
 * @module module/Uploader
 */
import { default as razyui } from '../index.js';
import { UploaderDef as DEF } from './Uploader.def.js';
import Uploader from './Uploader/index.js';

// ── Module registration ──
razyui.Uploader = Uploader;

// ── JIT Component Definition registration ──
if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

// ── Custom Element registration ──
/**
 * Registers the Uploader component as a custom element.
 * This function is called asynchronously to ensure the custom element registry is available.
 *
 * @async
 * @function registerElement
 * @returns {Promise<void>} A promise that resolves when the element is registered.
 */
export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Uploader);
}

export default Uploader;
export const stylesheet = null;
