/**
 * @fileoverview Uploader — class orchestrator.
 *
 * Imports helpers, state, view, and event modules, wiring them
 * together via private fields in one cohesive class.
 *
 * @module module/Uploader/index
 */

import { default as razyui } from '../../index.js';
import { CLS, DEFAULTS, STATUS } from './constants.js';
import { fmtSize, createEntry } from './helpers.js';
import { addToQueue, removeFromQueue, getQueuedEntries } from './state.js';
import { buildUploaderDOM, renderEntry, updateEntryDOM, removeEntryDOM, destroyDOM } from './view.js';
import { bindDropZone, bindFileInput, bindBrowseButton, bindListRemove } from './events.js';

const { isFn, isStr, isPO } = razyui;

// ── Class ─────────────────────────────────────

/**
 * Uploader component.
 * @class Uploader
 */
const Uploader = class {

    /** @type {HTMLElement} */
    #container  = null;  // raw element
    /** @type {Object} */
    #els        = null;  // Elements wrapper
    /** @type {Object} */
    #config     = {};
    /** @type {HTMLInputElement} */
    #fileInput  = null;
    /** @type {HTMLElement} */
    #dropArea   = null;
    /** @type {HTMLElement} */
    #listEl     = null;
    /** @type {Array} */
    #queue      = [];    // { file, id, preview?, status, xhr? }
    /** @type {boolean} */
    #destroyed  = false;
    /** @type {number} */
    #idCounter  = 0;
    /** @type {AbortController} */
    #eventAC         = new AbortController();

    /**
     * Creates an instance of Uploader.
     * @param {string|HTMLElement} selector - The container element or selector.
     * @param {Object} [config={}] - Configuration options.
     */
    constructor(selector, config = {}) {
        const el = isStr(selector) ? razyui(selector)[0] : selector;
        if (!el) { console.warn('Uploader: element not found \u2192', selector); return; }

        this.#container = el;
        this.#els = razyui(el);
        this.#config = { ...DEFAULTS, ...config };
        this.#init();
    }

    // ── Build DOM ─────────────────────────────
    /**
     * Builds the DOM structure for the Uploader.
     * @private
     */
    #init() {
        const cfg = this.#config;
        const { fileInput, dropArea, listEl } = buildUploaderDOM(this.#container, cfg);

        this.#fileInput = fileInput;
        this.#dropArea  = dropArea;
        this.#listEl    = listEl;

        // Bind drop zone events
        if (cfg.dropZone && dropArea) {
            bindDropZone(dropArea, fileInput, (files) => this.#addFiles(files), this.#eventAC.signal);
        } else {
            // Bind browse button (non-dropzone mode)
            const browseBtn = this.#els.find('.uploader-browse')[0];
            if (browseBtn) bindBrowseButton(browseBtn, fileInput, this.#eventAC.signal);
        }

        // Bind file input change
        bindFileInput(fileInput, (files) => this.#addFiles(files), this.#eventAC.signal);

        // Bind delegated remove-button click
        bindListRemove(listEl, (id) => this.#removeEntryById(id), this.#eventAC.signal);
    }

    // ── Add files to queue ────────────────────
    /**
     * Adds files to the upload queue.
     * @param {FileList|File[]} fileList - The list of files to add.
     * @private
     */
    #addFiles(fileList) {
        const cfg = this.#config;
        const files = [...fileList];

        for (const file of files) {
            // Max files check
            if (cfg.maxFiles > 0 && this.#queue.length >= cfg.maxFiles) break;

            // Max size check
            if (cfg.maxSize > 0 && file.size > cfg.maxSize) {
                if (isFn(cfg.onError)) cfg.onError(file, `File exceeds max size (${fmtSize(cfg.maxSize)})`);
                continue;
            }

            // onFileAdded guard
            if (isFn(cfg.onFileAdded) && cfg.onFileAdded(file) === false) continue;

            const entry = createEntry(file, ++this.#idCounter);
            addToQueue(this.#queue, entry);
            renderEntry(entry, cfg, this.#listEl);
        }

        if (cfg.auto) this.#uploadAll();
    }

    // ── Remove entry ──────────────────────────
    /**
     * Removes an entry from the queue and DOM.
     * @param {Object} entry - The entry to remove.
     * @private
     */
    #removeEntry(entry) {
        removeFromQueue(this.#queue, entry);
        removeEntryDOM(entry.id, this.#listEl);
        if (isFn(this.#config.onRemove)) this.#config.onRemove(entry.file);
    }

    /**
     * Removes an entry by its string id (used by delegated click).
     * @param {string} id - The ID of the entry to remove.
     * @private
     */
    #removeEntryById(id) {
        const entry = this.#queue.find(e => String(e.id) === String(id));
        if (entry) this.#removeEntry(entry);
    }

    // ── Upload ────────────────────────────────
    /**
     * Uploads all queued entries.
     * @private
     */
    #uploadAll() {
        const queued = getQueuedEntries(this.#queue);
        for (const entry of queued) {
            this.#uploadOne(entry);
        }
        this.#syncBusy();
    }

    #syncBusy() {
        const busy = this.#queue.some(e => e.status === STATUS.UPLOADING);
        this.#container.setAttribute('aria-busy', String(busy));
    }

    /**
     * Uploads a single entry.
     * @param {Object} entry - The entry to upload.
     * @private
     */
    #uploadOne(entry) {
        const cfg = this.#config;
        let url = cfg.url;
        if (isFn(url)) url = url(entry.file);
        if (!url) return;

        entry.status = STATUS.UPLOADING;
        entry.progress = 0;
        updateEntryDOM(entry, this.#listEl);

        if (isFn(cfg.onUpload)) cfg.onUpload(entry.file);

        const xhr = new XMLHttpRequest();
        entry.xhr = xhr;
        const formData = new FormData();
        formData.append(cfg.name, entry.file);

        // Append extra data fields
        if (isPO(cfg.data)) {
            for (const [k, v] of Object.entries(cfg.data)) {
                formData.append(k, v);
            }
        }

        xhr.upload.addEventListener('progress', (e) => {
            if (e.lengthComputable) {
                entry.progress = Math.round((e.loaded / e.total) * 100);
                updateEntryDOM(entry, this.#listEl);
                if (isFn(cfg.onProgress)) cfg.onProgress(entry.file, entry.progress);
            }
        });

        xhr.addEventListener('load', () => {
            entry.status = STATUS.DONE;
            entry.progress = 100;
            updateEntryDOM(entry, this.#listEl);

            let response = xhr.responseText;
            try { response = JSON.parse(response); } catch (_) {}
            if (isFn(cfg.onComplete)) cfg.onComplete(entry.file, response);
            this.#syncBusy();
        });

        xhr.addEventListener('error', () => {
            entry.status = STATUS.ERROR;
            updateEntryDOM(entry, this.#listEl);
            if (isFn(cfg.onError)) cfg.onError(entry.file, 'Upload failed');
            this.#syncBusy();
        });

        xhr.addEventListener('abort', () => {
            entry.status = STATUS.ERROR;
            updateEntryDOM(entry, this.#listEl);
            this.#syncBusy();
        });

        xhr.open(cfg.method, url, true);

        // Extra headers
        if (isPO(cfg.headers)) {
            for (const [k, v] of Object.entries(cfg.headers)) {
                xhr.setRequestHeader(k, v);
            }
        }

        xhr.send(formData);
    }

    // ── Public API ────────────────────────────
    /**
     * Gets the controller object for the Uploader instance.
     * @returns {Object} The controller object.
     */
    getControl() {
        const self = this;
        return {            get action()   { return self.#config.url; },
            set action(v)  { self.#config.url = v; },
            get accept()   { return self.#config.accept; },
            set accept(v)  { self.#config.accept = v; },
            get multiple() { return self.#config.multiple; },
            set multiple(v){ self.#config.multiple = !!v; },
            get maxSize()  { return self.#config.maxSize; },
            set maxSize(v) { self.#config.maxSize = Number(v); },
            get required() { return self.#fileInput.required; },
            set required(v){ self.#fileInput.required = !!v; self.#container.setAttribute('aria-required', String(!!v)); },
            checkValidity:     () => self.#fileInput.checkValidity(),
            reportValidity:    () => self.#fileInput.reportValidity(),
            setCustomValidity: (m) => self.#fileInput.setCustomValidity(m || ''),
            get label()       { return self.#container.getAttribute('aria-label'); },
            set label(v)      { v ? self.#container.setAttribute('aria-label', v) : self.#container.removeAttribute('aria-label'); },
            get labelledby()  { return self.#container.getAttribute('aria-labelledby'); },
            set labelledby(v) { v ? self.#container.setAttribute('aria-labelledby', v) : self.#container.removeAttribute('aria-labelledby'); },
            get describedby() { return self.#container.getAttribute('aria-describedby'); },
            set describedby(v){ v ? self.#container.setAttribute('aria-describedby', v) : self.#container.removeAttribute('aria-describedby'); },
            get loading()     { return self.#queue.some(e => e.status === STATUS.UPLOADING); },
            upload:   () => self.#uploadAll(),
            clear:    () => { [...self.#queue].forEach(e => self.#removeEntry(e)); },
            getFiles: () => self.#queue.map(e => e.file),
            addFiles: (files) => self.#addFiles(files),
            destroy:  () => self.#destroy(),
            get element() { return self.#container; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /**
     * Destroys the Uploader instance, cleaning up DOM and events.
     * @private
     */
    #destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        // Abort pending
        this.#queue.forEach(e => { if (e.xhr) e.xhr.abort(); });
        destroyDOM(this.#container);
    }
};

export default Uploader;
