/**
 * @fileoverview Uploader constants — CSS classes, defaults, status values.
 * @module module/Uploader/constants
 */

import Icons from '../Icons.js';
import { defineParts } from '../shared/definePart.js';

// ── CSS class names ─────────────────────────────

/** CSS class map used throughout the Uploader component. */
export const CLS = Object.freeze({
    ROOT:           'uploader',
    INPUT:          'uploader-input',
    DROP:           'uploader-drop',
    DROP_ICON:      'uploader-drop-icon',
    DROP_TEXT:      'uploader-drop-text',
    BROWSE:         'uploader-browse btn',
    LIST:           'uploader-list',
    FILE:           'uploader-file',
    THUMB:          'uploader-thumb',
    INFO:           'uploader-info',
    NAME:           'uploader-name',
    SIZE:           'uploader-size',
    PROGRESS:       'uploader-progress',
    PROGRESS_FILL:  'uploader-progress-fill',
    STATUS:         'uploader-status',
    REMOVE:         'uploader-remove',
    DRAGOVER:       'is-dragover',
    UPLOADING:      'is-uploading',
    DONE:           'is-done',
    ERROR:          'is-error',
});

// ── Entry status values ─────────────────────────

/** Possible status values for a queue entry. */
export const STATUS = Object.freeze({
    QUEUED:    'queued',
    UPLOADING: 'uploading',
    DONE:      'done',
    ERROR:     'error',
});

// ── Default configuration ───────────────────────

/** Default configuration values merged with user-supplied config. */
export const DEFAULTS = Object.freeze({
    url:         '',
    method:      'POST',
    name:        'file',
    maxFiles:    0,
    maxSize:     0,
    accept:      '',
    auto:        false,
    dropZone:    true,
    preview:     true,
    multiple:    true,
    placeholder: 'Drag files here or click to browse',
    headers:     null,
    data:        null,
    onFileAdded: null,
    onUpload:    null,
    onProgress:  null,
    onComplete:  null,
    onError:     null,
    onRemove:    null,
});

// ── Icons / labels ──────────────────────────────

/** Default icon for drag-and-drop zone. */
export const DROP_ICON = Icons.svg('upload', { size: 24, strokeWidth: 1.5 });

/** Default icon for non-image file thumbnails. */
export const FILE_ICON = Icons.svg('file', { size: 24, strokeWidth: 1.5 });

/** Label for the remove button. */
export const REMOVE_LABEL = Icons.svg('x', { size: 12, strokeWidth: 2 });

/** Label for the browse button. */
export const BROWSE_LABEL = 'Browse...';

/** Semantic part names for JIT styling overrides. */
export const PART = defineParts('Uploader', {
    ROOT        : { class: 'uploader', aliases: ['root', 'container'] },
    INPUT       : { class: 'uploader-input', tag: 'input' },
    DROP        : { class: 'uploader-drop', aliases: ['drop', 'dropzone'] },
    DROP_ICON   : { class: 'uploader-drop-icon' },
    DROP_TEXT   : { class: 'uploader-drop-text' },
    BROWSE      : { class: 'uploader-browse', tag: 'button' },
    LIST        : { class: 'uploader-list', aliases: ['list'] },
    FILE        : { class: 'uploader-file', aliases: ['file'] },
    THUMB       : { class: 'uploader-thumb' },
    INFO        : { class: 'uploader-info' },
    NAME        : { class: 'uploader-name' },
    SIZE        : { class: 'uploader-size' },
    PROGRESS    : { class: 'uploader-progress' },
    PROGRESS_FILL: { class: 'uploader-progress-fill' },
    STATUS      : { class: 'uploader-status', tag: 'span' },
    REMOVE      : { class: 'uploader-remove', aliases: ['remove'], tag: 'button' },
});

PART.ROOT.jit     = 'relative';
PART.INPUT.jit    = 'absolute w-0 h-0 [opacity:0] [pointer-events:none]';
PART.DROP.jit     = 'flex flex-col items-center justify-center gap-[var(--up-drop-gap)] [padding:var(--up-drop-padding-y)_var(--up-drop-padding-x)] [border:var(--up-drop-border-width)_dashed_var(--rui-border)] rounded-[var(--up-drop-radius)] bg-[var(--rui-bg-raised)] cursor-pointer [transition:border-color_var(--rui-transition-normal),background_var(--rui-transition-normal)] select-none hover:[border-color:var(--rui-accent)] hover:bg-[var(--rui-accent-subtle)] {is-dragover}:[border-color:var(--rui-accent)] {is-dragover}:bg-[var(--rui-accent-subtle)]';
PART.DROP_ICON.jit = 'text-[var(--up-icon-font-size)]';
PART.DROP_TEXT.jit = 'text-[var(--up-text-font-size)] fg-[var(--rui-text-muted)]';
PART.BROWSE.jit   = 'cursor-pointer';
PART.LIST.jit     = 'flex flex-col gap-[var(--up-list-gap)] [margin-top:var(--up-list-margin-top)] empty:[margin-top:0]';
PART.FILE.jit     = 'flex items-center gap-[var(--up-file-gap)] [padding:var(--up-file-padding-y)_var(--up-file-padding-x)] [border:1px_solid_var(--rui-border)] rounded-[var(--up-file-radius)] bg-[var(--rui-bg)] text-[var(--up-file-font-size)] [transition:border-color_var(--rui-transition-normal)] {is-done}:[border-color:var(--rui-success)] {is-error}:[border-color:var(--rui-danger)] {is-uploading}:[border-color:var(--rui-accent)] {is-uploading}:[opacity:0.8]';
PART.THUMB.jit    = 'shrink-0 w-[var(--up-thumb-size)] [height:36px] rounded-[var(--up-thumb-radius)] overflow-hidden bg-[var(--rui-bg-inset)] flex items-center justify-center text-[1.1rem] [&_img]:w-full [&_img]:h-full [&_img]:[object-fit:cover]';
PART.INFO.jit     = 'flex-1 min-w-0 flex flex-col gap-[1px]';
PART.NAME.jit     = 'text-nowrap overflow-hidden [text-overflow:ellipsis] fw-500';
PART.SIZE.jit     = 'text-[0.72rem] fg-[var(--rui-text-muted)]';
PART.PROGRESS.jit = 'shrink-0 w-[80px] [height:4px] rounded-[var(--rui-radius-sm)] bg-[var(--rui-bg-inset)] overflow-hidden';
PART.PROGRESS_FILL.jit = 'h-full w-0 rounded-[var(--rui-radius-sm)] bg-[var(--rui-accent)] [transition:width_var(--rui-transition-normal)_var(--rui-transition-easing)] ^{is-done}:bg-[var(--rui-success)] ^{is-done}:w-full ^{is-error}:bg-[var(--rui-danger)]';
PART.STATUS.jit   = 'shrink-0 w-[42px] text-right text-[0.72rem] fg-[var(--rui-text-muted)] ^{is-done}:fg-[var(--rui-success)] ^{is-error}:fg-[var(--rui-danger)]';
PART.REMOVE.jit   = 'shrink-0 w-[22px] h-[22px] flex items-center justify-center [border:none] rounded-[var(--up-thumb-radius)] [background:transparent] fg-[var(--rui-text-muted)] cursor-pointer text-[0.75rem] [transition:background_var(--rui-transition-normal),color_var(--rui-transition-normal)] hover:bg-[var(--rui-danger-bg)] hover:fg-[var(--rui-danger)]';